diff --git a/Dapper/DbString.cs b/Dapper/DbString.cs
index 15b97d6..187387e 100644
--- a/Dapper/DbString.cs
+++ b/Dapper/DbString.cs
@@ -96,11 +96,23 @@ public void AddParameter(IDbCommand command, string name)
             {
                 param.Size = Length;
             }
-            param.DbType = IsAnsi ? (IsFixedLength ? DbType.AnsiStringFixedLength : DbType.AnsiString) : (IsFixedLength ? DbType.StringFixedLength : DbType.String);
+            // If IsAnsi was not explicitly set (defaults to IsAnsiDefault which is false),
+            // detect whether the provider is ANSI-only and override accordingly.
+            bool effectiveIsAnsi = IsAnsi || IsAnsiProvider(command.Connection);
+            param.DbType = effectiveIsAnsi ? (IsFixedLength ? DbType.AnsiStringFixedLength : DbType.AnsiString) : (IsFixedLength ? DbType.StringFixedLength : DbType.String);
             if (add)
             {
                 command.Parameters.Add(param);
             }
         }
+
+        private static bool IsAnsiProvider(IDbConnection? connection)
+        {
+            if (connection is null) return false;
+            string typeName = connection.GetType().FullName ?? "";
+            // OleDb and ODBC connections use ANSI string types
+            return typeName.IndexOf("oledb", StringComparison.OrdinalIgnoreCase) >= 0
+                || typeName.IndexOf("odbc", StringComparison.OrdinalIgnoreCase) >= 0;
+        }
